mapper.sql:
/* wms-outbound-oborderList-sql-oracle.xml - selectObOriOrdHdRefSql - WMS > 출고 관리 > 원 출고주문 현황 : 헤더 조회 SQL */ SELECT * FROM ( SELECT 0 AS CHK , OHR.CTKEY /*센터코드*/ , CT.CTNM /*센터명*/ , OHR.OWKEY /*화주코드*/ , OHR.OBHDDAY /*주문지시일시*/ , OHR.OBREQDATE /*출고희망일자*/ , MAX(OH.OBWKDATE) AS OBWKDATE /*작업일자*/ , OHR.OBCNFRMDATE /*출고완료일시*/ , OHR.OBORDKEY /*오더코드*/ , OHR.EXTERNORDERKEY /*고객주문번호*/ , OHR.OBHDTYPECD /*출고유형*/ , (CASE WHEN COUNT(OH.OBHDKEY) = SUM(CASE WHEN OH.OBSTATUSCD IN ('00') THEN 1 ELSE 0 END) THEN '10' /*출고대기*/ WHEN COUNT(OH.OBHDKEY) = SUM(CASE WHEN OH.OBSTATUSCD IN ('60','65','70') THEN 1 ELSE 0 END) THEN '20' /*출고완료*/ WHEN COUNT(OH.OBHDKEY) = SUM(CASE WHEN OH.OBSTATUSCD IN ('97','98','99') THEN 1 ELSE 0 END) THEN '30' /*출고취소*/ WHEN COUNT(OH.OBHDKEY) = SUM(CASE WHEN OH.OBSTATUSCD IN ('00','01','97','98','99') THEN 1 ELSE 0 END)THEN '10' /*출고대기*/ WHEN COUNT(OH.OBHDKEY) = SUM(CASE WHEN OH.OBSTATUSCD IN ('60','65','70','97','98','99') THEN 1 ELSE 0 END) THEN '20' /*출고완료*/ ELSE '40' END) AS OBSTATUSCD /*출고작업상태*/ , COUNT(DISTINCT OD.ICKEY) AS OB_ORD_SKU /*주문_SKU*/ , SUM(OD.INITQTY) AS OB_ORD_QTY /*주문_EA*/ , SUM(IC.SLPRC * OD.INITQTY) AS OB_ORD_SLPRC /*주문_금액*/ , COUNT(DISTINCT (CASE WHEN OD.ALQTY > 0 THEN OD.ICKEY END)) AS EXP_SKU /*예정_SKU*/ , SUM(CASE WHEN OD.ALQTY > 0 THEN OD.ALQTY ELSE 0 END) AS EXP_QTY /*예정_EA*/ , SUM(CASE WHEN OD.ALQTY > 0 THEN IC.SLPRC * OD.ALQTY ELSE 0 END) AS EXP_SLPRC /*예정_금액*/ , COUNT(DISTINCT (CASE WHEN OD.PKISTQTY > 0 THEN OD.ICKEY END)) AS ORDER_SKU /*지시_SKU*/ , SUM(CASE WHEN OD.PKISTQTY > 0 THEN OD.PKISTQTY ELSE 0 END) AS ORDER_QTY /*지시_EA*/ , SUM(CASE WHEN OD.PKISTQTY > 0 THEN IC.SLPRC * OD.PKISTQTY ELSE 0 END) AS ORDER_SLPRC /*지시_금액*/ , COUNT(DISTINCT CASE WHEN OD.CNFRMQTY > 0 THEN OD.ICKEY END) AS OB_SKU /*출고_SKU*/ , SUM(CASE WHEN OD.CNFRMQTY > 0 THEN OD.CNFRMQTY ELSE 0 END) AS OB_QTY /*출고_EA*/ , SUM(CASE WHEN OD.CNFRMQTY > 0 THEN IC.SLPRC * OD.CNFRMQTY ELSE 0 END) AS OB_SLPRC /*출고_금액*/ , OHR.CMT /*비고*/ , OHR.INSERTURKEY /*입력자*/ , OHR.INSERTDATE /*입력일시*/ , OHR.UPDATEURKEY /*수정자*/ , OHR.UPDATEDATE /*수정일시*/ FROM TWORK_INFO_OB_ORD_HD OHR INNER JOIN TWORK_INFO_OB_HD OH ON OHR.CTKEY = OH.CTKEY AND OHR.OWKEY = OH.OWKEY AND OHR.OBORDKEY = OH.OBORDKEY INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY INNER JOIN TWORK_MST_IC IC ON OD.CTKEY = IC.CTKEY AND OD.OWKEY = IC.OWKEY AND OD.ICKEY = IC.ICKEY INNER JOIN TWORK_MST_CT CT ON OHR.CTKEY = CT.CTKEY
INNER JOIN ( SELECT ORH.CTKEY , ORH.OWKEY , ORH.OBORDKEY FROM TWORK_INFO_OB_ORD_HD ORH INNER JOIN TWORK_INFO_OB_ORD_DT ORD ON ORH.CTKEY = ORD.CTKEY AND ORH.OWKEY = ORD.OWKEY AND ORH.OBORDKEY = ORD.OBORDKEY WHERE ORH.CTKEY = #{CTKEY} AND ORH.OBHDDAY BETWEEN #{OBHDDAY_FROM} AND #{OBHDDAY_TO} AND ORD.ICKEY IN
#{ic}
(#{ICKEY})
GROUP BY ORH.CTKEY , ORH.OWKEY , ORH.OBORDKEY ) ORIC ON OHR.CTKEY = ORIC.CTKEY AND OHR.OWKEY = ORIC.OWKEY AND OHR.OBORDKEY = ORIC.OBORDKEY
WHERE 1=1 AND OHR.CTKEY = #{CTKEY} AND OHR.OBHDDAY BETWEEN #{OBHDDAY_FROM} AND #{OBHDDAY_TO} GROUP BY OHR.CTKEY /*센터코드*/ , OHR.OWKEY /*화주코드*/ , CT.CTNM /*센터명*/ , OHR.OBHDDAY /*주문지시일시*/ , OHR.OBREQDATE /*출고희망일자*/ , OHR.OBCNFRMDATE /*출고완료일시*/ , OHR.OBORDKEY /*오더코드*/ , OHR.EXTERNORDERKEY /*고객주문번호*/ , OHR.OBHDDAY /*출고예정일자*/ , OHR.OBHDTYPECD /*출고유형*/ , OHR.CMT /*비고*/ , OHR.INSERTURKEY /*입력자*/ , OHR.INSERTDATE /*입력일시*/ , OHR.UPDATEURKEY /*수정자*/ , OHR.UPDATEDATE /*수정일시*/ ) A WHERE
#{SEARCH_CONDITION}

