/* wms-outbound-oborderList-sql-oracle.xml - selectObOriOrdHdCountNew - WMS > 출고 관리 > 원 출고주문 현황 : 헤더 조회 count */ SELECT COUNT(1) FROM ( SELECT OHR.CTKEY , OHR.OWKEY , OHR.OBORDKEY , MIN(CASE WHEN WH.WAHDKEY IS NULL THEN OH.OBWKDATE ELSE WH.WAHDDAY||'000000' END) AS OBWKDATE , (CASE WHEN COUNT(OH.OBHDKEY) = SUM(CASE WHEN OH.OBSTATUSCD IN ('00') THEN 1 ELSE 0 END) THEN '10' /*출고대기*/ WHEN COUNT(OH.OBHDKEY) = SUM(CASE WHEN OH.OBSTATUSCD IN ('60','65','70') THEN 1 ELSE 0 END) THEN '20' /*출고완료*/ WHEN COUNT(OH.OBHDKEY) = SUM(CASE WHEN OH.OBSTATUSCD IN ('97','98','99') THEN 1 ELSE 0 END) THEN '30' /*출고취소*/ WHEN COUNT(OH.OBHDKEY) = SUM(CASE WHEN OH.OBSTATUSCD IN ('00','01','97','98','99') THEN 1 ELSE 0 END)THEN '10' /*출고대기*/ WHEN COUNT(OH.OBHDKEY) = SUM(CASE WHEN OH.OBSTATUSCD IN ('60','65','70','97','98','99') THEN 1 ELSE 0 END) THEN '20' /*출고완료*/ ELSE '40' END) AS OBSTATUSCD FROM TWORK_INFO_OB_ORD_HD OHR INNER JOIN TWORK_INFO_OB_HD OH ON OHR.CTKEY = OH.CTKEY AND OHR.OWKEY = OH.OWKEY AND OHR.OBORDKEY = OH.OBORDKEY INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY INNER JOIN TWORK_MST_IC IC ON OD.CTKEY = IC.CTKEY AND OD.OWKEY = IC.OWKEY AND OD.ICKEY = IC.ICKEY LEFT OUTER JOIN TWORK_INFO_WA_HD WH ON OH.CTKEY = WH.CTKEY AND OH.OWKEY = WH.OWKEY AND OH.WAHDKEY = WH.WAHDKEY WHERE
#{SEARCH_CONDITION}
AND OD.ICKEY IN
#{ickey}
GROUP BY OHR.CTKEY, OHR.OWKEY, OHR.OBORDKEY ) WHERE 1=1
AND OBWKDATE BETWEEN #{OBWKFROMDATE} AND #{OBWKTODATE}
AND OBSTATUSCD IN
#{obstatuscd}

/* wms-outbound-oborderList-sql-oracle.xml - selectObOriOrdHdNew - WMS > 출고 관리 > 원 출고주문 현황 : 헤더 조회 조회 */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT OHR.CTKEY , CT.CTNM , OHR.OWKEY , OHR.OBHDDAY , OHR.OBREQDATE , MAIN.OBWKDATE , OHR.OBCNFRMDATE , OHR.OBORDKEY , OHR.EXTERNORDERKEY , OHR.OBHDTYPECD , MAIN.OBSTATUSCD , MAIN.OB_ORD_SKU , MAIN.OB_ORD_QTY , MAIN.OB_ORD_SLPRC , MAIN.EXP_SKU , MAIN.EXP_QTY , MAIN.EXP_SLPRC , MAIN.ORDER_SKU , MAIN.ORDER_QTY , MAIN.ORDER_SLPRC , MAIN.OB_SKU , MAIN.OB_QTY , MAIN.OB_SLPRC , OHR.CMT /*비고*/ , OHR.INSERTURKEY /*입력자*/ , OHR.INSERTDATE /*입력일시*/ , OHR.UPDATEURKEY /*수정자*/ , OHR.UPDATEDATE /*수정일시*/ FROM ( SELECT OHR.CTKEY , OHR.OWKEY , OHR.OBORDKEY , MIN(CASE WHEN WH.WAHDKEY IS NULL THEN OH.OBWKDATE ELSE WH.WAHDDAY||'000000' END) AS OBWKDATE , (CASE WHEN COUNT(OH.OBHDKEY) = SUM(CASE WHEN OH.OBSTATUSCD IN ('00') THEN 1 ELSE 0 END) THEN '10' /*출고대기*/ WHEN COUNT(OH.OBHDKEY) = SUM(CASE WHEN OH.OBSTATUSCD IN ('60','65','70') THEN 1 ELSE 0 END) THEN '20' /*출고완료*/ WHEN COUNT(OH.OBHDKEY) = SUM(CASE WHEN OH.OBSTATUSCD IN ('97','98','99') THEN 1 ELSE 0 END) THEN '30' /*출고취소*/ WHEN COUNT(OH.OBHDKEY) = SUM(CASE WHEN OH.OBSTATUSCD IN ('00','01','97','98','99') THEN 1 ELSE 0 END)THEN '10' /*출고대기*/ WHEN COUNT(OH.OBHDKEY) = SUM(CASE WHEN OH.OBSTATUSCD IN ('60','65','70','97','98','99') THEN 1 ELSE 0 END) THEN '20' /*출고완료*/ ELSE '40' END) AS OBSTATUSCD /*출고작업상태*/ , COUNT(DISTINCT OD.ICKEY) AS OB_ORD_SKU , SUM(OD.INITQTY) AS OB_ORD_QTY , SUM(IC.SLPRC * OD.INITQTY) AS OB_ORD_SLPRC , COUNT(DISTINCT CASE WHEN OD.ALQTY > 0 THEN OD.ICKEY END) AS EXP_SKU , SUM(OD.ALQTY) AS EXP_QTY , SUM(IC.SLPRC * OD.ALQTY) AS EXP_SLPRC , COUNT(DISTINCT CASE WHEN OD.PKISTQTY > 0 THEN OD.ICKEY END) AS ORDER_SKU , SUM(OD.PKISTQTY) AS ORDER_QTY , SUM(IC.SLPRC * OD.PKISTQTY) AS ORDER_SLPRC , COUNT(DISTINCT CASE WHEN OD.CNFRMQTY > 0 THEN OD.ICKEY END) AS OB_SKU , SUM(OD.CNFRMQTY) AS OB_QTY , SUM(IC.SLPRC * OD.CNFRMQTY) AS OB_SLPRC FROM TWORK_INFO_OB_ORD_HD OHR INNER JOIN TWORK_INFO_OB_HD OH ON OHR.CTKEY = OH.CTKEY AND OHR.OWKEY = OH.OWKEY AND OHR.OBORDKEY = OH.OBORDKEY INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY INNER JOIN TWORK_MST_IC IC ON OD.CTKEY = IC.CTKEY AND OD.OWKEY = IC.OWKEY AND OD.ICKEY = IC.ICKEY LEFT OUTER JOIN TWORK_INFO_WA_HD WH ON OH.CTKEY = WH.CTKEY AND OH.OWKEY = WH.OWKEY AND OH.WAHDKEY = WH.WAHDKEY WHERE
#{SEARCH_CONDITION}
AND OD.ICKEY IN
#{ickey}
GROUP BY OHR.CTKEY, OHR.OWKEY, OHR.OBORDKEY ) MAIN INNER JOIN TWORK_INFO_OB_ORD_HD OHR ON MAIN.CTKEY = OHR.CTKEY AND MAIN.OWKEY = OHR.OWKEY AND MAIN.OBORDKEY = OHR.OBORDKEY INNER JOIN TWORK_MST_CT CT ON OHR.CTKEY = CT.CTKEY WHERE 1=1
AND MAIN.OBWKDATE BETWEEN #{OBWKFROMDATE} AND #{OBWKTODATE}
AND MAIN.OBSTATUSCD IN
#{obstatuscd}
ORDER BY OHR.CTKEY, OHR.OWKEY, OHR.OBORDKEY #{GRIDPAGING_ROWNUMTYPE_BOTTOM}

