mapper.update:
/* wms-outbound-oborderList-sql-oracle.xml - updateObOriOrdCmt - WMS > 출고 관리 > 원 출고주문 현황 : 비고 저장 */
UPDATE TWORK_INFO_OB_ORD_HD
   SET CMT = #{cmt}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBORDKEY = #{obordkey}

mapper.sql:
/* wms-outbound-oborderList-sql-oracle.xml - selectObOrdHdRefSql - WMS > 출고 관리 > 출고 현황 : 헤더 조회 SQL */ SELECT OB.* FROM ( SELECT 0 AS CHK , OH.CTKEY /*센터코드*/ , CT.CTNM /*센터명*/ , OH.OWKEY /*화주코드*/ , OH.OBREQDATE /*주문지시일시*/ , OH.OBHDDAY /*출고희망일자*/ , OH.OBWKDATE /*작업일자*/ , OH.OBCNFRMDATE /*출고완료일시*/ , OH.OBORDKEY /*오더코드*/ , OH.OBHDKEY /*릴리즈코드*/ , OH.EXTERNORDERKEY /*고객주문번호*/ , OH.OBHDTYPECD /*출고유형*/ , OH.OBSTATUSCD /*진행상태*/ , COUNT(DISTINCT OD.ICKEY) AS OB_ORD_SKU /*주문_SKU*/ , SUM(OD.INITQTY) AS OB_ORD_QTY /*주문_EA*/ , SUM(IC.SLPRC * OD.INITQTY) AS OB_ORD_SLPRC /*주문_금액*/ , COUNT(DISTINCT (CASE WHEN OD.ALQTY > 0 THEN OD.ICKEY END)) AS EXP_SKU /*예정_SKU*/ , SUM(CASE WHEN OD.ALQTY > 0 THEN OD.ALQTY ELSE 0 END) AS EXP_QTY /*예정_EA*/ , SUM(CASE WHEN OD.ALQTY > 0 THEN IC.SLPRC * OD.ALQTY ELSE 0 END) AS EXP_SLPRC /*예정_금액*/ , COUNT(DISTINCT (CASE WHEN OD.PKISTQTY > 0 THEN OD.ICKEY END)) AS ORDER_SKU /*지시_SKU*/ , SUM(CASE WHEN OD.PKISTQTY > 0 THEN OD.PKISTQTY ELSE 0 END) AS ORDER_QTY /*지시_EA*/ , SUM(CASE WHEN OD.PKISTQTY > 0 THEN IC.SLPRC * OD.PKISTQTY ELSE 0 END) AS ORDER_SLPRC /*지시_금액*/ , COUNT(DISTINCT CASE WHEN OD.CNFRMQTY > 0 THEN OD.ICKEY END) AS OB_SKU /*출고_SKU*/ , SUM(CASE WHEN OD.CNFRMQTY > 0 THEN OD.CNFRMQTY ELSE 0 END) AS OB_QTY /*출고_EA*/ , SUM(CASE WHEN OD.CNFRMQTY > 0 THEN IC.SLPRC * OD.CNFRMQTY ELSE 0 END) AS OB_SLPRC /*출고_금액*/ , COUNT(DISTINCT NIS.ICKEY) AS NIS_EXP_SKU , SUM(NIS.EXPCTQTY) AS NIS_EXP_QTY , SUM(IC.SLPRC * COALESCE(NIS.EXPCTQTY, 0)) AS NIS_EXP_SLPRC , COUNT(DISTINCT (CASE WHEN NIS.NISQTY > 0 THEN NIS.ICKEY ELSE NULL END)) AS NIS_CNFRM_SKU , SUM(CASE WHEN NIS.NISQTY > 0 THEN NIS.NISQTY ELSE 0 END) AS NIS_CNFRM_QTY , SUM(CASE WHEN NIS.NISQTY > 0 THEN IC.SLPRC * COALESCE(NIS.NISQTY, 0) ELSE 0 END) AS NIS_CNFRM_SLPRC , OH.CBM /*총CBM*/ , OH.WEIGHT / 1000 AS WEIGHT /*총중량*/ , OH.CLASSIFSPECCD /*DAS규격*/ , OH.ORDSEPTYPECD /*주문분리유형*/ , OH.WKTYPECD /*작업유형*/ , (SELECT WH.WAHDNM FROM TWORK_INFO_WA_HD WH WHERE OH.CTKEY = WH.CTKEY AND OH.OWKEY = WH.OWKEY AND OH.WAHDKEY = WH.WAHDKEY) AS WAHDNM /*WAVE*/ , OH.WBLNO /*송장번호*/ , OH.RECOMBOXBARCODE /*추천박스*/ , BOX_REC.BOXNM AS RECOMBOXNM , OH.PCKGBOXBARCODE /*출고박스*/ , BOX_PCKG.BOXNM AS PCKGBOXNM , OH.CMT /*비고*/ , OH.ORDSEPURKEY /*주문분리자*/ , OH.ORDSEPDATE /*주문분리일시*/ , OH.OBWKISTURKEY /*작업지시자*/ , OH.OBWKDATE AS OBWKDT /*작업지시일시*/ , OH.PCKGURKEY /*포장작업자*/ , OH.PCKGDATE /*포장작업일자*/ , OH.INSERTURKEY /*입력자*/ , OH.INSERTDATE /*입력일시*/ , OH.UPDATEURKEY /*수정자*/ , OH.UPDATEDATE /*수정일시*/ , OH.WKCNLREQYN /*작업취소요청여부*/ , OH.WAHDKEY , OH.PIHDKEY /*피킹헤더코드*/ , (CASE WHEN SUM(CASE WHEN IC.PKOTICYN = 'Y' THEN 1 ELSE 0 END) > 0 THEN 'Y' ELSE 'N' END) AS PKOTICYN /*덕용여부*/ , (CASE WHEN SUM(CASE WHEN IC.ROBSORTERICYN = 'Y' THEN 1 ELSE 0 END) > 0 THEN 'Y' ELSE 'N' END) AS ROBSORTERICYN /*로봇여부*/ , (CASE WHEN SUM(CASE WHEN OD.EXPCTQTY >= ( SELECT ICUTXCTN.ICUNITQTY FROM TWORK_MST_ICUTXTYPE ICUTXCTN WHERE OD.CTKEY = ICUTXCTN.CTKEY AND OD.OWKEY = ICUTXCTN.OWKEY AND OD.ICKEY = ICUTXCTN.ICKEY AND OD.ICUNITKEY = ICUTXCTN.ICUNITKEY AND ICUTXCTN.ICUNITTYPECD = 'CTN' ) THEN 1 ELSE 0 END ) > 0 THEN 'Y' ELSE 'N' END) AS CTN_YN /*카톤입수여부*/ , COUNT(OD.ICKEY) AS SKU , SUM(OD.EXPCTQTY) AS PCS , OH.CLASSIFCNTRBARCODE /*분류TOTE*/ , CNTR.CNTRBARCODE
, MAX(GREATEST(COALESCE(ICUTX.WIDTH, 0), COALESCE(ICUTX.DEPTH, 0), COALESCE(ICUTX.HEIGHT, 0))) AS MAXLEN /*상품길이*/ , SUM(CASE WHEN IC.ROBSORTERICYN = 'N' THEN OD.EXPCTQTY ELSE 0 END) AS FBQTY /*이형물QTY*/ , ROUND(COUNT(CASE WHEN IC.ROBSORTERICYN = 'Y' THEN 1 END) * 100 / COUNT(*), 0) AS RBRATIO /*로봇소터비율*/ FROM TWORK_INFO_OB_HD OH
INNER JOIN ( SELECT OH.CTKEY , OH.OWKEY , OH.OBHDKEY FROM TWORK_INFO_OB_HD OH INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY INNER JOIN TWORK_MST_ICUTXTYPE ICUTX ON OD.CTKEY = ICUTX.CTKEY AND OD.OWKEY = ICUTX.OWKEY AND OD.ICKEY = ICUTX.ICKEY AND OD.ICUNITKEY = ICUTX.ICUNITKEY AND OD.UOM = ICUTX.ICUNITTYPECD WHERE OH.CTKEY = #{CTKEY}
AND OH.OWKEY = COALESCE(#{OWKEY}, #{sowkey})
AND OH.OBHDDAY BETWEEN #{OBHDDAY_FROM} AND #{OBHDDAY_TO}
AND OD.ICKEY IN
#{ickey}
AND (ICUTX.VOL * OD.EXPCTQTY) > #{OVERSCHEDIT}
AND (ICUTX.WEIGHT * OD.EXPCTQTY) / 1000 > #{OVERSCHEDIT}
AND OD.EXPCTQTY > #{OVERSCHEDIT}
AND GREATEST(COALESCE(ICUTX.WIDTH, 0), COALESCE(ICUTX.DEPTH, 0), COALESCE(ICUTX.HEIGHT, 0)) BETWEEN #{MAXLENFR} AND #{MAXLENTO}
GROUP BY OH.CTKEY , OH.OWKEY , OH.OBHDKEY ) FIL ON OH.CTKEY = FIL.CTKEY AND OH.OWKEY = FIL.OWKEY AND OH.OBHDKEY = FIL.OBHDKEY
INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY INNER JOIN TWORK_MST_IC IC ON OD.CTKEY = IC.CTKEY AND OD.OWKEY = IC.OWKEY AND OD.ICKEY = IC.ICKEY INNER JOIN TWORK_MST_ICUTXTYPE ICUTX ON OD.CTKEY = ICUTX.CTKEY AND OD.OWKEY = ICUTX.OWKEY AND OD.ICKEY = ICUTX.ICKEY AND OD.ICUNITKEY = ICUTX.ICUNITKEY AND OD.UOM = ICUTX.ICUNITTYPECD INNER JOIN TWORK_MST_CT CT ON OH.CTKEY = CT.CTKEY LEFT OUTER JOIN TWORK_MST_BOX BOX_REC ON OH.CTKEY = BOX_REC.CTKEY AND OH.RECOMBOXBARCODE = BOX_REC.BOXBARCODE LEFT OUTER JOIN TWORK_MST_BOX BOX_PCKG ON OH.CTKEY = BOX_PCKG.CTKEY AND OH.PCKGBOXBARCODE = BOX_PCKG.BOXBARCODE LEFT OUTER JOIN TWORK_INFO_OB_NIS_DT NIS ON OD.CTKEY = NIS.CTKEY AND OD.OWKEY = NIS.OWKEY AND OD.OBHDKEY = NIS.OBHDKEY AND OD.OBDTKEY = NIS.OBDTKEY LEFT OUTER JOIN ( SELECT PD.CTKEY, PD.OWKEY, PD.OBHDKEY, MAX(PC.CNTRBARCODE) AS CNTRBARCODE FROM TWORK_INFO_PI_DT PD INNER JOIN TWORK_INFO_PK_CNTR_DT PC ON PD.CTKEY = PC.CTKEY AND PD.OWKEY = PC.OWKEY AND PD.PIHDKEY = PC.PIHDKEY AND PD.PIDTKEY = PC.PIDTKEY WHERE PC.CNTRBARCODE IS NOT NULL GROUP BY PD.CTKEY, PD.OWKEY, PD.OBHDKEY ) CNTR ON OH.CTKEY = CNTR.CTKEY AND OH.OWKEY = CNTR.OWKEY AND OH.OBHDKEY = CNTR.OBHDKEY WHERE OH.CTKEY = #{CTKEY} AND OH.OWKEY = COALESCE(#{OWKEY}, #{sowkey}) AND OH.OBHDDAY BETWEEN #{OBHDDAY_FROM} AND #{OBHDDAY_TO} GROUP BY OH.CTKEY /*센터코드*/ , CT.CTNM /*센터명*/ , OH.OWKEY /*화주코드*/ , OH.OBREQDATE /*주문지시일시*/ , OH.OBHDDAY /*출고희망일자*/ , OH.OBWKDATE /*작업일자*/ , OH.OBCNFRMDATE /*출고완료일시*/ , OH.OBORDKEY /*오더*/ , OH.OBHDKEY /*릴리즈코드*/ , OH.EXTERNORDERKEY /*고객주문번호*/ , OH.OBHDTYPECD /*출고유형*/ , OH.OBSTATUSCD /*진행상태*/ , OH.CBM /*총CBM*/ , OH.WEIGHT /*총중량*/ , OH.CLASSIFSPECCD /*DAS규격*/ , OH.ORDSEPTYPECD /*주문분리유형*/ , OH.WKTYPECD /*작업유형*/ , OH.WBLNO /*송장번호*/ , OH.RECOMBOXBARCODE /*추천박스*/ , BOX_REC.BOXNM , OH.PCKGBOXBARCODE /*출고박스*/ , BOX_PCKG.BOXNM , OH.CMT /*비고*/ , OH.ORDSEPURKEY /*주문분리자*/ , OH.ORDSEPDATE /*주문분리일시*/ , OH.OBWKISTURKEY /*작업지시자*/ , OH.PCKGURKEY /*포장작업자*/ , OH.PCKGDATE /*포장작업일시*/ , OH.INSERTURKEY /*입력자*/ , OH.INSERTDATE /*입력일시*/ , OH.UPDATEURKEY /*수정자*/ , OH.UPDATEDATE /*수정일시*/ , OH.WAHDKEY , OH.WKCNLREQYN /*작업취소요청여부*/ , OH.CLASSIFCNTRBARCODE /*분류TOTE*/ , CNTR.CNTRBARCODE , OH.PIHDKEY /*피킹헤더코드*/ ) OB WHERE
#{SEARCH_CONDITION}

