/* wms-outbound-oborderList-sql-oracle.xml - selectObOrdHd - WMS > 출고 관리 > 출고 현황 : 헤더 조회 조회 */
#{GRIDPAGING_ROWNUMTYPE_TOP}
SELECT 	*
  FROM (

