/* wms-outbound-oborderList-sql-oracle.xml - selectObOrdHdNewRefSql - WMS > 출고 관리 > 출고 현황 : 주문별 탭 조회 SQL */ SELECT * FROM ( SELECT 0 AS CHK , MAIN.CTKEY , MAIN.OWKEY , CT.CTNM , OH.OBREQDATE /*주문지시일시*/ , OH.OBHDDAY /*출고희망일자*/ , CASE WHEN WH.WAHDKEY IS NULL THEN OH.OBWKDATE ELSE WH.WAHDDAY||'000000' END AS OBWKDATE /*작업일자*/ , OH.OBCNFRMDATE /*출고완료일시*/ , OH.OBORDKEY /*오더코드*/ , OH.OBHDKEY /*릴리즈코드*/ , OH.EXTERNORDERKEY /*고객주문번호*/ , OH.OBHDTYPECD /*출고유형*/ , OH.OBSTATUSCD /*진행상태*/ , OH.CBM /*총CBM*/ , OH.WEIGHT / 1000 AS WEIGHT /*총중량*/ , OH.CLASSIFSPECCD /*DAS규격*/ , OH.ORDSEPTYPECD /*주문분리유형*/ , OH.WKTYPECD /*작업유형*/ , (SELECT WAHDNM FROM TWORK_INFO_WA_HD WH WHERE WH.CTKEY = OH.CTKEY AND WH.OWKEY = OH.OWKEY AND WH.WAHDKEY = OH.WAHDKEY) AS WAHDNM , OH.WBLNO /*송장번호*/ , OH.RECOMBOXBARCODE /*추천박스*/ , BOX_REC.BOXNM AS RECOMBOXNM , OH.PCKGBOXBARCODE /*출고박스*/ , BOX_PCKG.BOXNM AS PCKGBOXNM , OH.CMT /*비고*/ , OH.ORDSEPURKEY /*주문분리자*/ , OH.ORDSEPDATE /*주문분리일시*/ , OH.OBWKISTURKEY /*작업지시자*/ , OH.OBWKDATE AS OBWKDT /*작업지시일시*/ , OH.PCKGURKEY /*포장작업자*/ , OH.PCKGDATE /*포장작업일자*/ , OH.INSERTURKEY /*입력자*/ , OH.INSERTDATE /*입력일시*/ , OH.UPDATEURKEY /*수정자*/ , OH.UPDATEDATE /*수정일시*/ , OH.WKCNLREQYN /*작업취소요청여부*/ , COALESCE(MAIN.SKU_COUNT, 0) AS SKU_COUNT , COALESCE(MAIN.ORD_SKU, 0) AS OB_ORD_SKU , COALESCE(MAIN.ORD_QTY, 0) AS OB_ORD_QTY , COALESCE(MAIN.ORD_SLPRC, 0) AS OB_ORD_SLPRC , COALESCE(MAIN.EXP_SKU, 0) AS EXP_SKU , COALESCE(MAIN.EXP_QTY, 0) AS EXP_QTY , COALESCE(MAIN.EXP_SLPRC, 0) AS EXP_SLPRC , COALESCE(MAIN.IST_SKU, 0) AS ORDER_SKU , COALESCE(MAIN.IST_QTY, 0) AS ORDER_QTY , COALESCE(MAIN.IST_SLPRC, 0) AS ORDER_SLPRC , COALESCE(MAIN.OB_SKU, 0) AS OB_SKU , COALESCE(MAIN.OB_QTY, 0) AS OB_QTY , COALESCE(MAIN.OB_SLPRC, 0) AS OB_SLPRC , COALESCE(MAIN.NIS_EXP_SKU, 0) AS NIS_CNFRM_SKU , COALESCE(MAIN.NIS_EXP_QTY, 0) AS NIS_CNFRM_QTY , COALESCE(MAIN.NIS_EXP_SLPRC, 0) AS NIS_CNFRM_SLPRC FROM ( SELECT OH.CTKEY ,OH.OWKEY , OH.OBHDKEY , COUNT(DISTINCT OD.ICKEY) AS SKU_COUNT , COUNT(DISTINCT OD.ICKEY) AS ORD_SKU , SUM(OD.INITQTY) AS ORD_QTY , SUM(IC.SLPRC * OD.INITQTY) AS ORD_SLPRC , COUNT(DISTINCT CASE WHEN OD.ALQTY > 0 THEN OD.ICKEY END) AS EXP_SKU , SUM(OD.ALQTY) AS EXP_QTY , SUM(IC.SLPRC * OD.ALQTY) AS EXP_SLPRC , COUNT(DISTINCT CASE WHEN OD.PKISTQTY > 0 THEN OD.ICKEY END) AS IST_SKU , SUM(OD.PKISTQTY) AS IST_QTY , SUM(IC.SLPRC * OD.PKISTQTY) AS IST_SLPRC , COUNT(DISTINCT CASE WHEN OD.CNFRMQTY > 0 THEN OD.ICKEY END) AS OB_SKU , SUM(OD.CNFRMQTY) AS OB_QTY , SUM(IC.SLPRC * OD.CNFRMQTY) AS OB_SLPRC , COUNT(DISTINCT CASE WHEN OD.NISQTY > 0 THEN OD.ICKEY END) AS NIS_EXP_SKU , SUM(OD.NISQTY) AS NIS_EXP_QTY , SUM(IC.SLPRC * OD.NISQTY) AS NIS_EXP_SLPRC FROM TWORK_INFO_OB_HD OH INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY INNER JOIN TWORK_MST_IC IC ON OD.CTKEY = IC.CTKEY AND OD.OWKEY = IC.OWKEY AND OD.ICKEY = IC.ICKEY LEFT OUTER JOIN ( SELECT PD.CTKEY, PD.OWKEY, PD.OBHDKEY, MAX(PC.CNTRBARCODE) AS CNTRBARCODE FROM TWORK_INFO_PI_DT PD INNER JOIN TWORK_INFO_PK_CNTR_DT PC ON PD.CTKEY = PC.CTKEY AND PD.OWKEY = PC.OWKEY AND PD.PIHDKEY = PC.PIHDKEY AND PD.PIDTKEY = PC.PIDTKEY GROUP BY PD.CTKEY, PD.OWKEY, PD.OBHDKEY ) CNTR ON OH.CTKEY = CNTR.CTKEY AND OH.OWKEY = CNTR.OWKEY AND OH.OBHDKEY = CNTR.OBHDKEY WHERE #{SEARCH_CONDITION}
AND OH.OBSTATUSCD IN
#{obstatuscd}
GROUP BY OH.CTKEY, OH.OWKEY, OH.OBHDKEY ) MAIN INNER JOIN TWORK_INFO_OB_HD OH ON MAIN.CTKEY = OH.CTKEY AND MAIN.OWKEY = OH.OWKEY AND MAIN.OBHDKEY = OH.OBHDKEY /* LEFT OUTER JOIN ( SELECT ND.CTKEY, ND.OWKEY, ND.OBHDKEY, COUNT(DISTINCT ND.ICKEY) AS NIS_EXP_SKU, SUM(ND.EXPCTQTY) AS NIS_EXP_QTY, SUM(ND.EXPCTQTY * IC.SLPRC) AS NIS_EXP_SLPRC -- 예시 (필요시 IC 조인) FROM TWORK_INFO_OB_NIS_DT ND INNER JOIN TWORK_MST_IC IC ON ND.CTKEY = IC.CTKEY AND ND.OWKEY = IC.OWKEY AND ND.ICKEY = IC.ICKEY WHERE ND.CTKEY = '09' AND ND.OWKEY = 'DAISO' GROUP BY ND.CTKEY, ND.OWKEY, ND.OBHDKEY ) NIS ON OH.CTKEY = NIS.CTKEY AND OH.OWKEY = NIS.OWKEY AND OH.OBHDKEY = NIS.OBHDKEY */ INNER JOIN TWORK_MST_CT CT ON OH.CTKEY = CT.CTKEY LEFT OUTER JOIN TWORK_MST_BOX BOX_REC ON OH.CTKEY = BOX_REC.CTKEY AND OH.RECOMBOXBARCODE = BOX_REC.BOXBARCODE LEFT OUTER JOIN TWORK_MST_BOX BOX_PCKG ON OH.CTKEY = BOX_PCKG.CTKEY AND OH.PCKGBOXBARCODE = BOX_PCKG.BOXBARCODE LEFT OUTER JOIN TWORK_INFO_WA_HD WH ON OH.CTKEY = WH.CTKEY AND OH.OWKEY = WH.OWKEY AND OH.WAHDKEY = WH.WAHDKEY ) A
WHERE A.OBWKDATE BETWEEN #{OBWKFROMDATE} AND #{OBWKTODATE}
ORDER BY A.CTKEY, A.OWKEY, A.OBHDKEY

/* wms-outbound-oborderList-sql-oracle.xml - selectObOrdDetailRefSql - WMS > 출고 관리 > 출고 현황 : 상세별 탭 조회 SQL */ SELECT OB.* FROM ( SELECT 0 AS CHK , OH.CTKEY /*센터코드*/ , CT.CTNM /*센터명*/ , OH.OWKEY /*화주코드*/ , OH.OBREQDATE /*주문지시일시*/ , OH.OBHDDAY /*출고희망일자*/ , CASE WHEN WH.WAHDKEY IS NULL THEN OH.OBWKDATE ELSE WH.WAHDDAY||'000000' END AS OBWKDATE /*작업일자*/ , OH.OBCNFRMDATE /*출고완료일시*/ , OH.OBORDKEY /*오더코드*/ , OH.OBHDKEY /*릴리즈코드*/ , OH.EXTERNORDERKEY /*고객주문번호*/ , OH.OBHDTYPECD /*출고유형*/ , OH.OBSTATUSCD /*출고상태*/ , OD.OBDTSTATUSCD /*출고상세상태*/ , OD.ICKEY /*상품코드*/ , IC.ICNM /*상품명*/ , IC.SLPRC /*단가*/ , IC.PKOTICYN /*덕용여부*/ , IC.ROBSORTERICYN /*로봇여부*/ , (SELECT ICUTXCTN.ICUNITQTY FROM TWORK_MST_ICUTXTYPE ICUTXCTN WHERE OD.CTKEY = ICUTXCTN.CTKEY AND OD.OWKEY = ICUTXCTN.OWKEY AND OD.ICKEY = ICUTXCTN.ICKEY AND OD.ICUNITKEY = ICUTXCTN.ICUNITKEY AND ICUTXCTN.ICUNITTYPECD = 'CTN') AS ICUNITQTY /*카톤입수*/ , OD.INITQTY /*주문수량*/ , OD.EXPCTQTY /*예정수량*/ , OD.ALQTY /*할당수량*/ , OD.PKISTQTY /*지시수량*/ , OD.PKQTY /*피킹수량*/ , COALESCE(OD.PKISTQTY, 0) - COALESCE(OD.PKQTY, 0) AS INCQTY /* 미피킹수량*/ , OD.CNFRMQTY /*출고수량*/ , OD.NISQTY AS NIS_CNFRM_QTY /*결품수량*/ , COALESCE(OD.INITQTY, 0) * COALESCE(IC.SLPRC, 0) AS AMT /*금액*/ , ICUTX.VOL * OD.INITQTY AS CBM /*총CBM*/ , (ICUTX.WEIGHT * OD.INITQTY) / 1000 AS WEIGHT /*총중량*/ , OH.CLASSIFSPECCD /*DAS규격*/ , OH.ORDSEPTYPECD /*주문유형*/ , OH.WKTYPECD /*작업유형*/ , OH.WAHDKEY , (SELECT WH.WAHDNM FROM TWORK_INFO_WA_HD WH WHERE OH.CTKEY = WH.CTKEY AND OH.OWKEY = WH.OWKEY AND OH.WAHDKEY = WH.WAHDKEY) AS WAHDNM /*WAVE*/ , OH.WBLNO /*송장번호*/ , OH.RECOMBOXBARCODE /*추천박스*/ , BOX_REC.BOXNM AS RECOMBOXNM , OH.PCKGBOXBARCODE /*출고박스*/ , BOX_PCKG.BOXNM AS PCKGBOXNM , OH.CLASSIFCNTRBARCODE /*분류TOTE*/ , CNTR.CNTRBARCODE , CNTR.CNTRWKURKEY , CNTR.CNTRDDLNYN , OH.CMT /*비고*/ , OH.ORDSEPURKEY /*주문분리자*/ , OH.ORDSEPDATE /*주문분리일시*/ , OH.OBWKISTURKEY /*작업지시자*/ , OH.OBWKDATE AS OBWKDT /*작업지시일시*/ , OH.PCKGURKEY /*포장작업자*/ , OH.PCKGDATE /*포장작업일시*/ , OD.INSERTURKEY /*입력자*/ , OD.INSERTDATE /*입력일시*/ , OD.UPDATEURKEY /*수정자*/ , OD.UPDATEDATE /*수정일시*/ , OH.WKCNLREQYN /*작업취소요청여부*/ , 1 AS SKU , OD.EXPCTQTY AS PCS , (CASE WHEN OD.EXPCTQTY >= ( SELECT ICUTXCTN.ICUNITQTY FROM TWORK_MST_ICUTXTYPE ICUTXCTN WHERE OD.CTKEY = ICUTXCTN.CTKEY AND OD.OWKEY = ICUTXCTN.OWKEY AND OD.ICKEY = ICUTXCTN.ICKEY AND OD.ICUNITKEY = ICUTXCTN.ICUNITKEY AND ICUTXCTN.ICUNITTYPECD = 'CTN' ) THEN 'Y' ELSE 'N' END) AS CTN_YN /*카톤입수여부*/ , CASE WHEN IC.ROBSORTERICYN = 'N' THEN OD.EXPCTQTY ELSE 0 END AS FBQTY /*이형물QTY*/ , COALESCE(ICUTX.VOL, 0) AS VOL , COALESCE(ICUTX.WEIGHT, 0) AS WEIGHT_ORI , COALESCE(ICUTX.WIDTH, 0) AS WIDTH , COALESCE(ICUTX.DEPTH, 0) AS DEPTH , COALESCE(ICUTX.HEIGHT, 0) AS HEIGHT , GREATEST(COALESCE(ICUTX.WIDTH, 0), COALESCE(ICUTX.DEPTH, 0), COALESCE(ICUTX.HEIGHT, 0)) AS MAXLEN /*상품길이*/ FROM TWORK_INFO_OB_HD OH INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY INNER JOIN TWORK_MST_CT CT ON OH.CTKEY = CT.CTKEY INNER JOIN TWORK_MST_IC IC ON OD.CTKEY = IC.CTKEY AND OD.OWKEY = IC.OWKEY AND OD.ICKEY = IC.ICKEY INNER JOIN TWORK_MST_ICUTXTYPE ICUTX ON OD.CTKEY = ICUTX.CTKEY AND OD.OWKEY = ICUTX.OWKEY AND OD.ICKEY = ICUTX.ICKEY AND ICUTX.ICUNITTYPECD = OD.UOM LEFT OUTER JOIN TWORK_MST_BOX BOX_REC ON OH.CTKEY = BOX_REC.CTKEY AND OH.RECOMBOXBARCODE = BOX_REC.BOXBARCODE LEFT OUTER JOIN TWORK_MST_BOX BOX_PCKG ON OH.CTKEY = BOX_PCKG.CTKEY AND OH.PCKGBOXBARCODE = BOX_PCKG.BOXBARCODE LEFT OUTER JOIN ( SELECT PD.CTKEY , PD.OWKEY , PD.OBHDKEY , PD.OBDTKEY , STRING_AGG(PK.CNTRBARCODE, ', ' ORDER BY PD.CTKEY, PD.OWKEY, PD.OBHDKEY, PD.OBDTKEY) AS CNTRBARCODE , STRING_AGG(PK.CNTRWKURKEY, ', ' ORDER BY PD.CTKEY, PD.OWKEY, PD.OBHDKEY, PD.OBDTKEY) AS CNTRWKURKEY , STRING_AGG(PK.CNTRDDLNYN, ', ' ORDER BY PD.CTKEY, PD.OWKEY, PD.OBHDKEY, PD.OBDTKEY) AS CNTRDDLNYN FROM TWORK_INFO_PI_DT PD INNER JOIN TWORK_INFO_PK_CNTR_DT PC ON PD.CTKEY = PC.CTKEY AND PD.OWKEY = PC.OWKEY AND PD.PIHDKEY = PC.PIHDKEY AND PD.PIDTKEY = PC.PIDTKEY INNER JOIN TWORK_INFO_PK_CNTR PK ON PC.CTKEY = PK.CTKEY AND PC.OWKEY = PK.OWKEY AND PC.PIHDKEY = PK.PIHDKEY AND PC.CNTRBARCODE = PK.CNTRBARCODE WHERE PC.CNTRBARCODE IS NOT NULL GROUP BY PD.CTKEY , PD.OWKEY , PD.OBHDKEY , PD.OBDTKEY ) CNTR ON OH.CTKEY = CNTR.CTKEY AND OH.OWKEY = CNTR.OWKEY AND OH.OBHDKEY = CNTR.OBHDKEY AND OD.OBDTKEY = CNTR.OBDTKEY LEFT OUTER JOIN TWORK_INFO_WA_HD WH ON OH.CTKEY = WH.CTKEY AND OH.OWKEY = WH.OWKEY AND OH.WAHDKEY = WH.WAHDKEY ) OB WHERE
#{SEARCH_CONDITION}
AND OBSTATUSCD IN
#{obstatuscd}
AND OBDTSTATUSCD IN
#{obdtstatuscd}
AND ICKEY IN
#{ickey}
AND OWKEY = COALESCE(#{OWKEY}, #{sowkey})
AND (VOL * EXPCTQTY) > #{OVERSCHEDIT}
AND (WEIGHT_ORI * EXPCTQTY) / 1000 > #{OVERSCHEDIT}
AND EXPCTQTY > #{OVERSCHEDIT}
AND GREATEST(COALESCE(WIDTH, 0), COALESCE(DEPTH, 0), COALESCE(HEIGHT, 0)) BETWEEN #{MAXLENFR} AND #{MAXLENTO}
AND OBWKDATE BETWEEN #{OBWKFROMDATE} AND #{OBWKTODATE}

