/* wms-outbound-oborderList-sql-oracle.xml - selectObOrdHdDetail - WMS > 출고 관리 > 출고 현황 : 상세별 탭 조회 조회 */
#{GRIDPAGING_ROWNUMTYPE_TOP}
SELECT 	*
  FROM (

  )
 ORDER BY
	   OBHDKEY
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

/* wms-outbound-oborderList-sql-oracle.xml - selectObOrdSummarySep - WMS > 출고 관리 > 출고 현황 > 출고요약장표 조회(주문유형) */
SELECT ORDSEPTYPECD
	 , COUNT(*) AS SEP_CNT
	 , ROUND(RATIO_TO_REPORT(COUNT(*)) OVER() * 100, 2) AS SEP_RATIO
  FROM TWORK_INFO_OB_HD
 WHERE CTKEY = #{ctkey}
   AND OWKEY = COALESCE(#{owkey}, #{sowkey})
   AND OBHDDAY  BETWEEN #{obhddayFr} AND #{obhddayTo}

   AND OBWKDATE BETWEEN #{obwkdayFr} AND #{obwkdayTo}


   AND WKTYPECD = #{wktypecd}

 GROUP BY
	   ORDSEPTYPECD
 ORDER BY
	   ORDSEPTYPECD

/* wms-outbound-oborderList-sql-oracle.xml - selectObOrdSummaryWk - WMS > 출고 관리 > 출고 현황 > 출고요약장표 조회(작업유형) */
SELECT WKTYPECD
	 , COUNT(*) AS WK_CNT
	 , ROUND(RATIO_TO_REPORT(COUNT(*)) OVER() * 100, 2) AS WK_RATIO
  FROM TWORK_INFO_OB_HD
 WHERE CTKEY = #{ctkey}
   AND OWKEY = COALESCE(#{owkey}, #{sowkey})
   AND OBHDDAY  BETWEEN #{obhddayFr} AND #{obhddayTo}

   AND OBWKDATE BETWEEN #{obwkdayFr} AND #{obwkdayTo}


   AND WKTYPECD = #{wktypecd}

 GROUP BY
	   WKTYPECD
 ORDER BY
	   WKTYPECD

/* wms-outbound-obOrdSep-sql-oracle.xml - selectObOrdDetailSummary - WMS > 출고 관리 > 출고 현황 > 출고요약장표 출고건수 조회 */ SELECT OB.CTKEY , OB.OWKEY , SUM(CASE OB.OBSTATUSCD WHEN '00' THEN 1 ELSE 0 END) AS WK_TARGET /*작업대상*/ , COUNT(OB.OBHDKEY) AS TOT_SUMMURY /*총합계*/ , SUM(CASE WHEN OB.OBSTATUSCD IN ('01','05','10') THEN 1 ELSE 0 END) AS WK_EXPCT /*작업예정*/ , SUM(CASE OB.OBSTATUSCD WHEN '01' THEN 1 ELSE 0 END) AS WK_UNASSIGNED /*미할당*/ , SUM(CASE OB.OBSTATUSCD WHEN '05' THEN 1 ELSE 0 END) AS WK_PARTIAL_ALLOCATE /*부분할당*/ , SUM(CASE OB.OBSTATUSCD WHEN '10' THEN 1 ELSE 0 END) AS WK_COMP_ALLOCATE /*할당완료*/ , SUM(CASE WHEN OB.OBSTATUSCD IN ('20','25','30') THEN 1 ELSE 0 END) AS WK_PK /*피킹*/ , SUM(CASE OB.OBSTATUSCD WHEN '20' THEN 1 ELSE 0 END) AS WK_PK_IST /*피킹지시*/ , SUM(CASE OB.OBSTATUSCD WHEN '25' THEN 1 ELSE 0 END) AS WK_PARTIAL_PK /*부분피킹*/ , SUM(CASE OB.OBSTATUSCD WHEN '30' THEN 1 ELSE 0 END) AS WK_PK_CNFRM /*피킹확정*/ , SUM(CASE WHEN OB.OBSTATUSCD IN ('80','85') THEN 1 ELSE 0 END) AS WK_NIS /*결품*/ , SUM(CASE OB.OBSTATUSCD WHEN '80' THEN 1 ELSE 0 END) AS WK_NIS_HOLD /*결품보류*/ , SUM(CASE OB.OBSTATUSCD WHEN '85' THEN 1 ELSE 0 END) AS WK_NIS_HOLD_COMP /*결품확정*/ , SUM(CASE WHEN OB.OBSTATUSCD IN ('40','45','50') THEN 1 ELSE 0 END) AS WK_PCKG /*포장*/ , SUM(CASE OB.OBSTATUSCD WHEN '40' THEN 1 ELSE 0 END) AS WK_UN_PAK /*미패킹*/ , SUM(CASE OB.OBSTATUSCD WHEN '45' THEN 1 ELSE 0 END) AS WK_PARTIAL_PAK /*부분패킹*/ , SUM(CASE OB.OBSTATUSCD WHEN '50' THEN 1 ELSE 0 END) AS WK_COMP_PAK /*패킹완료*/ , SUM(CASE WHEN OB.OBSTATUSCD IN ('60','65','70') THEN 1 ELSE 0 END) AS WK_OB /*출고*/ , SUM(CASE OB.OBSTATUSCD WHEN '60' THEN 1 ELSE 0 END) AS WK_UNOB /*미출고*/ , SUM(CASE OB.OBSTATUSCD WHEN '65' THEN 1 ELSE 0 END) AS WK_PATIAL_OB /*부분출고*/ , SUM(CASE OB.OBSTATUSCD WHEN '70' THEN 1 ELSE 0 END) AS WK_OB_COMPL /*출고완료*/ , SUM(CASE WHEN OB.OBSTATUSCD IN ('99','98','97') THEN 1 ELSE 0 END) AS WK_CANCEL /*취소*/ , SUM(CASE OB.OBSTATUSCD WHEN '99' THEN 1 ELSE 0 END) AS WK_ORD_CNL /*주문취소*/ , SUM(CASE OB.OBSTATUSCD WHEN '98' THEN 1 ELSE 0 END) AS WK_NIS_CNL /*결품취소*/ , SUM(CASE OB.OBSTATUSCD WHEN '97' THEN 1 ELSE 0 END) AS WK_WK_CNL /*작업취소*/ FROM TWORK_INFO_OB_HD OB WHERE CTKEY = #{ctkey} AND OWKEY = COALESCE(#{owkey}, #{sowkey}) AND OBHDDAY BETWEEN #{obhddayFr} AND #{obhddayTo}
AND OBWKDATE BETWEEN #{obwkdayFr} AND #{obwkdayTo}
AND WKTYPECD = #{wktypecd}
GROUP BY OB.CTKEY , OB.OWKEY
